  ('disabled-e0adf6cd-moex-00138', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-112-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '關於行政契約之執行，下列敘述何者正確？', '["行政契約本身即得作為行政強制執行之執行名義", "人民不履行契約義務時，行政機關原則上得作成行政處分命其履行；不 履行時，得為行政執行", "行政契約如有自願接受執行之約定，債務人不履行時，債權人無須藉由 行政訴訟取得執行名義", "行政機關不履行契約義務時，如有自願接受執行之約定，得準用行政執 行法為執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00139', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-112-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '依司法院釋字第785號解釋意旨，下列敘述何者錯誤？', '["公務人員保障法所規定之申訴與再申訴制度並不違憲", "依法提起行政訴訟之權利不應因公務人員之身分而有異", "對公務人員之影響，如屬顯然輕微之干預，即難謂構成權利之侵害", "服勤、休假之頻率與休息最低時數，屬工作條件，尚無涉公務人員服公 職權與健康權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
  ('disabled-e0adf6cd-moex-00140', 'disabled-e0adf6cd', 'disabled-e0adf6cd-moex-112-3082b5f1', 'sub-disabled-e0adf6cd-05', NULL, 'single_choice', '下列何者非行政處分？', '["拒絕某外國人入籍我國之申請", "氣象主管機關發布豪大雨警報", "劃設特定公用道路為行人徒步區", "認定某私有建築物為違章建築"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:15+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "304", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "教育行政"}'::jsonb, NULL),
